                      </div>
                      <h3 className={`text-2xl font-black ${importLog.success ? 'text-slate-900' : 'text-red-900'}`}>
                        {importLog.success ? 'Stock Updated' : 'Import Failed'}
                      </h3>
                      <p className="mt-3 font-bold text-slate-400 text-sm max-w-xs leading-relaxed">
                        {importLog.message}
