    }
  }, [activeTab]);

  const loadHistory = async () => {
    setLoading(true);
    const data = await fetchTransactions(
      TransactionStatus.APPROVED, 
      [TransactionType.SALE, TransactionType.RETURN]
    );
    setHistory(data);
    setLoading(false);
  };

  const loadSalesForReturn = async () => {
    setLoading(true);
    const salesData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.SALE);
    const returnsData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.RETURN);

    const returnedMap = new Map<string, number>();
    returnsData.forEach(r => {
        if (r.relatedTransactionId) {
            const current = returnedMap.get(r.relatedTransactionId) || 0;
            returnedMap.set(r.relatedTransactionId, current + r.quantity);
        }
    });
    setAlreadyReturnedMap(returnedMap);

    const availableSales = salesData.filter(sale => {
        const returnedQty = returnedMap.get(sale.id) || 0;
        return sale.quantity > returnedQty;
    });

    setSalesLog(availableSales);
    setLoading(false);
  };

  // --- COMPUTED FILTERED HISTORY ---
  const filteredHistory = useMemo(() => {
    let result = [...history];

    // 1. Search filter
    if (historySearch) {
      const s = historySearch.toLowerCase();
      result = result.filter(tx => 
        tx.partNumber.toLowerCase().includes(s) || 
        tx.customerName.toLowerCase().includes(s)
      );
    }

    // 2. Type filter
    if (typeFilter !== 'ALL') {
      result = result.filter(tx => tx.type === typeFilter);
    }

    // 3. Date range filter
    if (dateRange !== 'ALL') {
      const now = new Date();
      const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

      result = result.filter(tx => {
        const txTime = new Date(tx.createdAt).getTime();
        if (dateRange === 'TODAY') return txTime >= startOfToday;
        if (dateRange === 'WEEK') return txTime >= (now.getTime() - 7 * 24 * 60 * 60 * 1000);
        if (dateRange === 'MONTH') return txTime >= (now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return true;
      });
    }

    // 4. Amount range filter
    const min = parseFloat(minAmount);
    const max = parseFloat(maxAmount);
    if (!isNaN(min)) result = result.filter(tx => (tx.price * tx.quantity) >= min);
    if (!isNaN(max)) result = result.filter(tx => (tx.price * tx.quantity) <= max);

    // 5. Sorting
    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : (a.price * a.quantity);
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : (b.price * b.quantity);

      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });

    return result;
  }, [history, historySearch, typeFilter, dateRange, minAmount, maxAmount, sortBy, sortOrder]);

  const handleReturnToggle = (tx: Transaction) => {
    const newSelection = { ...selectedReturns };
    if (newSelection[tx.id]) {
      delete newSelection[tx.id];
    } else {
      const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
      const remaining = tx.quantity - prevReturned;
      newSelection[tx.id] = remaining > 0 ? remaining : 0;
    }
    setSelectedReturns(newSelection);
  };

  const handleReturnQtyChange = (txId: string, maxQty: number, newQty: string) => {
    let qty = parseInt(newQty);
    if (isNaN(qty)) qty = 0;
    if (qty > maxQty) qty = maxQty;
    if (qty < 0) qty = 0;

    if (qty === 0) {
      const newSelection = { ...selectedReturns };
      delete newSelection[txId];
      setSelectedReturns(newSelection);
    } else {
      setSelectedReturns({ ...selectedReturns, [txId]: qty });
    }
  };

  const submitReturns = async () => {
    const ids = Object.keys(selectedReturns);
    if (ids.length === 0) return;
    if (!confirm(`Process returns for ${ids.length} items?`)) return;

    setProcessingReturns(true);
    const returnPayload = ids.map(id => {
       const originalSale = salesLog.find(s => s.id === id);
       if (!originalSale) return null;
       return {
         partNumber: originalSale.partNumber,
         type: TransactionType.RETURN,
         quantity: selectedReturns[id],
         price: originalSale.price,
         customerName: originalSale.customerName || 'Customer Return',
         createdByRole: user.role,
         relatedTransactionId: originalSale.id
       };
    }).filter(Boolean) as any[];

    const res = await createBulkTransactions(returnPayload);
    setProcessingReturns(false);

    if (res.success) {
       alert("Returns processed successfully.");
       setSelectedReturns({});
       loadSalesForReturn();
    } else {
       alert("Failed to process returns: " + res.message);
    }
  };

  const filteredSalesLog = salesLog.filter(tx => 
     tx.partNumber.toLowerCase().includes(returnSearch.toLowerCase()) ||
     (tx.customerName && tx.customerName.toLowerCase().includes(returnSearch.toLowerCase()))
  );

  const totalRefundAmount = Object.keys(selectedReturns).reduce((acc, id) => {
     const tx = salesLog.find(s => s.id === id);
     return acc + (tx ? (tx.price * selectedReturns[id]) : 0);
  }, 0);

  const clearFilters = () => {
    setHistorySearch('');
    setTypeFilter('ALL');
    setDateRange('ALL');
    setMinAmount('');
    setMaxAmount('');
    setSortBy('date');
    setSortOrder('desc');
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 md:bg-transparent">

       {!isSearchingOnMobile && (
         <div className="md:hidden bg-white p-4 border-b border-slate-100 z-20 sticky top-0 shadow-sm animate-fade-in">
            <div className="flex bg-slate-100 p-1 rounded-2xl">
               <button 
                 onClick={() => setActiveTab('NEW')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'NEW' ? 'bg-white text-brand-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 Point of Sale
               </button>
               <button 
                 onClick={() => setActiveTab('RETURN')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'RETURN' ? 'bg-white text-rose-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 Returns
               </button>
               <button 
                 onClick={() => setActiveTab('HISTORY')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'HISTORY' ? 'bg-white text-slate-800 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 Log
               </button>
            </div>
         </div>
       )}

       <div className="hidden md:flex justify-between items-center mb-6">
          <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Counter Sales</h1>
             <p className="text-slate-500 font-medium">Record retail transactions and customer returns.</p>
          </div>
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-soft">
             <button onClick={() => setActiveTab('NEW')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'NEW' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <PlusCircle size={18} /> New Sale
             </button>
             <button onClick={() => setActiveTab('RETURN')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'RETURN' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <Undo2 size={18} /> Process Return
             </button>
             <button onClick={() => setActiveTab('HISTORY')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <History size={18} /> Recent History
             </button>
          </div>
       </div>

       <div className="flex-1 overflow-hidden flex flex-col relative">
          {activeTab === 'NEW' && (
             <DailyTransactions 
                user={user} 
                forcedMode="SALES" 
                onSearchToggle={setIsSearchingOnMobile} 
             />
          )}

          {activeTab === 'RETURN' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 text-rose-600 font-black text-base w-full md:w-auto">
                      <div className="p-2 bg-rose-50 rounded-xl"><Undo2 size={20} /></div>
                      SELECT ITEMS TO RETURN
                   </div>
                   <div className="w-full md:w-auto flex-1 md:max-w-xs relative">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                       <input 
                          type="text" 
                          placeholder="Search Part No. or Customer..."
                          className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-2xl text-sm font-bold shadow-inner focus:ring-2 focus:ring-rose-500/20"
                          value={returnSearch}
                          onChange={e => setReturnSearch(e.target.value)}
                       />
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
                   {loading ? (
                      <div className="flex justify-center p-12"><TharLoader /></div>
                   ) : filteredSalesLog.length === 0 ? (
                      <div className="flex flex-col items-center justify-center py-24 text-slate-300">
                         <AlertCircle size={64} className="mb-4 opacity-10" />
                         <p className="font-black text-xs uppercase tracking-widest">No compatible sales found</p>
                      </div>
                   ) : (
                      <div className="pb-24 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {filteredSalesLog.map(tx => {
                            const isSelected = !!selectedReturns[tx.id];
                            const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
                            const remainingQty = tx.quantity - prevReturned;
                            const returnQty = selectedReturns[tx.id] || remainingQty;

                            return (
                                <div 
                                    key={tx.id} 
                                    onClick={() => handleReturnToggle(tx)}
                                    className={`p-5 rounded-[2rem] border transition-all cursor-pointer bg-white ${isSelected ? 'border-rose-500 ring-2 ring-rose-500/10 shadow-lg' : 'border-slate-100 hover:border-slate-200 shadow-sm'}`}
                                >
                                    <div className="flex justify-between items-start mb-4">
                                        <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-rose-50 border-rose-50 text-white' : 'bg-slate-50 border-slate-200 text-transparent'}`}>
                                            <CheckCircle2 size={14} />
                                        </div>
                                        <div className="text-right">
                                            <div className="text-[9px] font-black text-slate-400 uppercase mb-0.5">Sold On</div>
                                            <div className="text-[11px] font-bold text-slate-900">{new Date(tx.createdAt).toLocaleDateString()}</div>
                                        </div>
                                    </div>

                                    <div className="mb-4">
                                        <div className="font-black text-lg text-slate-900 leading-tight">{tx.partNumber}</div>
                                        <div className="text-[13px] text-slate-400 font-medium flex items-center gap-1.5 mt-1">
                                            <UserIcon size={14} className="text-slate-300" /> {tx.customerName || 'Walk-in Customer'}
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-end border-t border-slate-50 pt-4">
                                        <div className="space-y-1">
                                            <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Original Sale</div>
                                            <div className="font-black text-slate-900">{tx.quantity} <span className="text-[10px] text-slate-400">units</span></div>
                                            <div className="text-[9px] font-black text-teal-600 bg-teal-50 px-1.5 py-0.5 rounded-md inline-block">Rem: {remainingQty}</div>
                                        </div>

                                        {isSelected && (
                                            <div onClick={e => e.stopPropagation()} className="bg-rose-50 p-2 rounded-2xl border border-rose-100 flex flex-col items-center">
                                                <span className="text-[9px] font-black text-rose-500 uppercase mb-1">Return Qty</span>
                                                <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                                                    <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (returnQty - 1).toString())} className="w-8 h-8 rounded-lg flex items-center justify-center text-rose-500"><Minus size={14}/></button>
                                                    <span className="font-black text-slate-900 min-w-[20px] text-center">{returnQty}</span>
                                                    <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (returnQty + 1).toString())} className="w-8 h-8 bg-rose-500 text-white rounded-lg flex items-center justify-center"><Plus size={14}/></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )
                        })}
                      </div>
                   )}
                </div>

                {/* Return Fixed Footer */}
                <div className="fixed bottom-0 md:bottom-6 left-0 md:left-auto right-0 md:right-8 bg-white md:rounded-3xl border-t md:border border-slate-100 p-5 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] md:shadow-2xl z-[90] pb-safe flex justify-between items-center md:min-w-[400px]">
                   <div className="flex-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Refund Total ({Object.keys(selectedReturns).length})</p>
                      <p className="text-2xl font-black text-rose-600 tracking-tight">₹{totalRefundAmount.toLocaleString()}</p>
                   </div>

                   <button 
                      onClick={submitReturns}
                      disabled={Object.keys(selectedReturns).length === 0 || processingReturns}
                      className="bg-rose-600 hover:bg-rose-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-rose-200 transition-all flex items-center gap-3 active:scale-95 disabled:opacity-30 disabled:shadow-none"
                   >
                      {processingReturns ? <Loader2 className="animate-spin" size={20} /> : <CheckCircle2 size={20} />}
                      Process
                   </button>
                </div>
             </div>
          )}

          {activeTab === 'HISTORY' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 w-full md:w-auto">
                      <div className="p-2 bg-slate-900 text-white rounded-xl"><History size={18} /></div>
                      <span className="font-black text-slate-900 text-base uppercase tracking-tight">Financial Journal</span>
                   </div>

                   <div className="flex items-center gap-2 w-full md:w-auto overflow-x-auto no-scrollbar pb-1 md:pb-0">
                      <div className="relative flex-1 md:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                         <input 
                           type="text" 
                           placeholder="Search History..." 
                           className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl text-sm font-bold shadow-inner focus:ring-2 focus:ring-slate-200"
                           value={historySearch}
                           onChange={e => setHistorySearch(e.target.value)}
                         />
                      </div>
                      <button 
                        onClick={() => setShowFilters(!showFilters)}
                        className={`p-2 rounded-xl border transition-all flex items-center gap-2 whitespace-nowrap text-xs font-bold ${showFilters ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
                      >
                         <Filter size={16} /> Filters {(typeFilter !== 'ALL' || dateRange !== 'ALL' || minAmount || maxAmount) && "•"}
                      </button>
                      <button 
                        onClick={loadHistory}
                        className="p-2 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-slate-600 transition-all"
                      >
                         <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                      </button>
                   </div>
                </div>

                {showFilters && (
                  <div className="bg-white border-b border-slate-100 p-4 md:p-6 animate-slide-down">
                    <div className="max-w-5xl mx-auto grid grid-cols-2 md:grid-cols-4 gap-4">
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tx Type</label>
                          <select 
                            className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                            value={typeFilter}
                            onChange={e => setTypeFilter(e.target.value as any)}
                          >
                             <option value="ALL">All Types</option>
                             <option value={TransactionType.SALE}>Sales Only</option>
                             <option value={TransactionType.RETURN}>Returns Only</option>
                          </select>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Period</label>
                          <select 
                            className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                            value={dateRange}
                            onChange={e => setDateRange(e.target.value as any)}
                          >
                             <option value="ALL">All Time</option>
                             <option value="TODAY">Today</option>
                             <option value="WEEK">Last 7 Days</option>
                             <option value="MONTH">Last 30 Days</option>
                          </select>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Amount Range (₹)</label>
                          <div className="flex items-center gap-2">
                             <input 
                               type="number" 
                               placeholder="Min" 
                               className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                               value={minAmount}
                               onChange={e => setMinAmount(e.target.value)}
                             />
                             <span className="text-slate-300">-</span>
                             <input 
                               type="number" 
                               placeholder="Max" 
                               className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                               value={maxAmount}
                               onChange={e => setMaxAmount(e.target.value)}
                             />
                          </div>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sort Order</label>
                          <div className="flex gap-2">
                            <select 
                                className="flex-1 bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                                value={sortBy}
                                onChange={e => setSortBy(e.target.value as any)}
                            >
                                <option value="date">Date</option>
                                <option value="amount">Amount</option>
                            </select>
                            <button 
                                onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
                                className="bg-slate-50 p-2.5 rounded-xl text-slate-500 hover:text-slate-900 transition-colors"
                            >
                                <ArrowUpDown size={16} />
                            </button>
                          </div>
                       </div>
                    </div>
                    <div className="flex justify-end mt-4">
                       <button onClick={clearFilters} className="text-[10px] font-black text-rose-500 uppercase tracking-widest hover:underline">Reset All Filters</button>
                    </div>
                  </div>
                )}

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                  {loading ? (
                    <div className="flex justify-center p-12"><TharLoader /></div>
                  ) : filteredHistory.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-24 text-slate-300">
                        <AlertCircle size={64} className="mb-4 opacity-10" />
                        <p className="font-black text-xs uppercase tracking-widest">No entries found matching filters</p>
                        <button onClick={clearFilters} className="mt-4 text-brand-600 font-bold text-xs uppercase tracking-widest">Clear All Filters</button>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                      {filteredHistory.map(tx => {
                          const isReturn = tx.type === TransactionType.RETURN;
                          const amount = tx.price * tx.quantity;
                          return (
                            <div key={tx.id} className={`p-5 rounded-[2rem] bg-white border border-slate-50 shadow-sm flex flex-col animate-fade-in relative overflow-hidden group`}>
                                {isReturn && <div className="absolute top-0 right-0 w-16 h-16 bg-rose-500/5 rotate-45 translate-x-8 -translate-y-8"></div>}

                                <div className="flex justify-between items-start mb-4">
                                    <div className="space-y-1">
                                        <div className="font-black text-slate-900 text-lg leading-tight group-hover:text-brand-600 transition-colors">{tx.partNumber}</div>
                                        <div className="flex items-center gap-1.5 text-slate-400 text-[11px] font-bold">
                                            <Calendar size={12} /> {new Date(tx.createdAt).toLocaleDateString()}
                                            <span className="text-slate-200">|</span>
                                            <Clock size={12} /> {new Date(tx.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                        </div>
                                    </div>
                                    <div className={`px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${isReturn ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>
                                        {isReturn ? <TrendingDown size={10} className="inline mr-1"/> : <TrendingUp size={10} className="inline mr-1"/>}
                                        {tx.type}
                                    </div>
                                </div>

                                <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-50 flex items-center gap-3 mb-5">
                                    <div className="w-8 h-8 bg-white rounded-xl flex items-center justify-center text-slate-300 shadow-sm border border-slate-100">
                                        <UserIcon size={14} />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-0.5">Billed To</p>
                                        <p className="text-[13px] font-bold text-slate-800 truncate">{tx.customerName || 'Walk-in Customer'}</p>
                                    </div>
                                </div>

                                <div className="mt-auto flex justify-between items-center">
                                    <div className="flex flex-col">
                                       <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest leading-none mb-1">Quantity</span>
                                       <span className="bg-slate-100 px-3 py-1 rounded-xl text-[11px] font-black text-slate-500 uppercase tracking-widest w-fit">
                                          {tx.quantity} units
                                       </span>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest leading-none mb-1">Net Value</p>
                                        <p className={`text-xl font-black tracking-tight ${isReturn ? 'text-rose-600' : 'text-slate-900'}`}>
                                            {isReturn ? '-' : ''}₹{amount.toLocaleString()}
                                        </p>
                                    </div>
                                </div>
                            </div>
                          );
                      })}
                    </div>
                  )}
                </div>
             </div>
          )}
       </div>
    </div>
  );
};

// Internal utility component for refresh icon animation
const RefreshCw: React.FC<{ className?: string }> = ({ className }) => (
  <svg 
    xmlns="http://www.w3.org/2000/svg" 
    width="24" 
    height="24" 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8" />
    <path d="M3 3v5h5" />
    <path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16" />
    <path d="M16 16h5v5" />
  </svg>
);

export default Billing;

import { GoogleGenAI, Type } from "@google/genai";
import { StockItem } from "../types";

export const generateInventoryInsights = async (inventory: StockItem[]): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const summary = inventory.map(i => 
      `- ${i.partNumber} (${i.brand}): ${i.quantity} units (Threshold: ${i.minStockThreshold})`
    ).join('\n');

    const prompt = `
      You are an inventory analyst for a car spare parts shop named "Sparezy".
      We stock Hyundai and Mahindra parts.

      Here is the current stock list status:
      ${summary}

      Please provide a concise strategic summary for the Business Owner.
      1. Identify critical shortages (Zero stock).
      2. Highlight low stock risks.
      3. Suggest which brand needs more immediate attention.
      4. Provide a short "Health Score" of the inventory out of 10.

      Keep it professional, actionable, and under 200 words.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Failed to generate AI insights. Please try again later.";
  }
};

export const extractInvoiceData = async (base64File: string, mimeType: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const filePart = {
      inlineData: {
        data: base64File,
        mimeType: mimeType,
      },
    };

    const prompt = `
      Extract details from this car spare parts invoice. 

      1. Identify the Dealer/Vendor Name (The company selling the parts).
      2. Identify the Invoice Date.
      3. Extract all line items with these specific fields:
         - Part Number (alphanumeric SKU)
         - Part Name/Description (the full descriptive name of the part)
         - Quantity (Qty)
         - MRP (Maximum Retail Price before discount)
         - B.DC % (Basic Discount percentage, typically around 12%)
         - Printed Net Unit Price (Final price for one unit shown on the bill)

      Ensure numerical values are clean numbers. 
      Return the data strictly as a JSON object.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [filePart, { text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            dealerName: { type: Type.STRING, description: "Name of the supplier/dealer" },
            invoiceDate: { type: Type.STRING, description: "Date on the invoice" },
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  partNumber: { type: Type.STRING },
                  name: { type: Type.STRING, description: "Descriptive name of the part" },
                  quantity: { type: Type.NUMBER },
                  mrp: { type: Type.NUMBER },
                  discountPercent: { type: Type.NUMBER, description: "B.DC percentage" },
                  printedUnitPrice: { type: Type.NUMBER, description: "The unit price shown on the bill after discount" }
                },
                required: ["partNumber", "name", "quantity", "mrp", "discountPercent", "printedUnitPrice"]
              }
            }
          },
          required: ["dealerName", "items"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Invoice Extraction Error:", error);
    throw new Error("Failed to read the invoice. Please ensure the document is clear.");
  }
};

import React, { useState, useEffect } from 'react';
import { User, Transaction, TransactionStatus, TransactionType } from '../types';
import DailyTransactions from './DailyTransactions';
import { 
  History, 
  PlusCircle, 
  PackageCheck, 
  FileUp, 
  Upload, 
  CheckCircle2, 
  AlertCircle, 
  Loader2, 
  X, 
  FileSpreadsheet,
  Info,
  ArrowRight,
  TrendingUp,
  Calendar,
  Truck,
  Clock,
  ChevronRight,
  Database,
  FileText,
  ScanLine,
  Share2,
  MessageCircle,
  Calculator,
  ShieldCheck,
  AlertTriangle,
  Percent,
  Building2
} from 'lucide-react';
import { fetchTransactions, createBulkTransactions } from '../services/transactionService';
import { extractInvoiceData } from '../services/geminiService';
import TharLoader from '../components/TharLoader';
import * as XLSX from 'xlsx';

interface Props {
  user: User;
}

interface ExtractedItem {
  partNumber: string;
  name: string;
  quantity: number;
  mrp: number;
  discountPercent: number;
  printedUnitPrice: number;
  calculatedPrice: number;
  hasError: boolean;
  errorType: 'DISCOUNT_LOW' | 'CALC_MISMATCH' | 'NONE';
  diff: number;
}

const Purchases: React.FC<Props> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'NEW' | 'IMPORT' | 'HISTORY'>('NEW');
  const [history, setHistory] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [isSearchingOnMobile, setIsSearchingOnMobile] = useState(false);

  // Bulk Import State
  const [importing, setImporting] = useState(false);
  const [importLog, setImportLog] = useState<{ success: boolean; message: string; count: number; totalValue: number; errorCount: number; dealer?: string } | null>(null);
  const [previewData, setPreviewData] = useState<ExtractedItem[]>([]);
  const [extractedMetadata, setExtractedMetadata] = useState<{ dealerName?: string; invoiceDate?: string }>({});
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const STANDARD_DISCOUNT = 12;

  useEffect(() => {
    if (activeTab === 'HISTORY') {
      loadHistory();
    }
  }, [activeTab]);

  const loadHistory = async () => {
    setLoading(true);
    const data = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.PURCHASE);
    setHistory(data);
    setLoading(false);
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleInvoiceUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setImporting(true);
    setErrorMsg(null);
    setPreviewData([]);
    setExtractedMetadata({});
    setImportLog(null);

    try {
      if (file.type === 'application/pdf' || file.type.startsWith('image/')) {
        const base64 = await fileToBase64(file);
        const result = await extractInvoiceData(base64, file.type);

        if (result && result.items && result.items.length > 0) {
          setExtractedMetadata({
            dealerName: result.dealerName,
            invoiceDate: result.invoiceDate
          });

          // Process verification logic with 12% rules
          const verifiedItems = result.items.map((item: any) => {
            const expectedPriceAt12Percent = item.mrp * (1 - (STANDARD_DISCOUNT / 100));
            const diff = Math.abs(expectedPriceAt12Percent - item.printedUnitPrice);

            let hasError = false;
            let errorType: 'DISCOUNT_LOW' | 'CALC_MISMATCH' | 'NONE' = 'NONE';

            if (item.discountPercent < STANDARD_DISCOUNT) {
              hasError = true;
              errorType = 'DISCOUNT_LOW';
            } else if (diff > 0.5) {
              hasError = true;
              errorType = 'CALC_MISMATCH';
            }

            return {
              ...item,
              calculatedPrice: parseFloat(expectedPriceAt12Percent.toFixed(2)),
              hasError,
              errorType,
              diff: parseFloat((item.printedUnitPrice - expectedPriceAt12Percent).toFixed(2))
            };
          });
          setPreviewData(verifiedItems);
        } else {
          throw new Error("No items detected in invoice.");
        }
      } else if (file.name.match(/\.(xlsx|xls|xlsb|xlsm|csv)$/i)) {
        const data = await file.arrayBuffer();
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as any[][];

        if (!jsonData || jsonData.length < 1) throw new Error("Spreadsheet is empty.");

        const parsed = jsonData.slice(1).map(row => {
          const mrp = Number(row[2] || 0);
          const disc = Number(row[3] || 0);
          const printed = Number(row[4] || mrp * (1 - disc/100));
          const calculatedAt12 = mrp * (1 - (STANDARD_DISCOUNT/100));

          let hasError = false;
          let errorType: 'DISCOUNT_LOW' | 'CALC_MISMATCH' | 'NONE' = 'NONE';

          if (disc < STANDARD_DISCOUNT) {
            hasError = true;
            errorType = 'DISCOUNT_LOW';
          } else if (Math.abs(printed - calculatedAt12) > 0.5) {
            hasError = true;
            errorType = 'CALC_MISMATCH';
          }

          return {
            partNumber: String(row[0] || ''),
            name: String(row[1] || 'Excel Row'),
            quantity: Number(row[5] || 1),
            mrp,
            discountPercent: disc,
            printedUnitPrice: printed,
            calculatedPrice: calculatedAt12,
            hasError,
            errorType,
            diff: printed - calculatedAt12
          };
        }).filter(i => i.partNumber && i.quantity > 0);

        setPreviewData(parsed as any);
      } else {
        throw new Error("Invalid file format.");
      }
    } catch (err: any) {
      setErrorMsg(err.message || "Extraction failed.");
    } finally {
      setImporting(false);
      e.target.value = '';
    }
  };

  const confirmBulkImport = async () => {
    if (previewData.length === 0) return;
    setImporting(true);

    const sourceName = extractedMetadata.dealerName 
      ? `${extractedMetadata.dealerName} (Inv: ${extractedMetadata.invoiceDate || 'N/A'})`
      : `AI Audit Scan (${new Date().toLocaleDateString()})`;

    const payload = previewData.map(item => ({
      partNumber: item.partNumber,
      type: TransactionType.PURCHASE,
      quantity: item.quantity,
      price: item.printedUnitPrice,
      customerName: sourceName,
      createdByRole: user.role
    }));

    const res = await createBulkTransactions(payload);

    if (res.success) {
      const total = payload.reduce((sum, item) => sum + (item.price * item.quantity), 0);
      const errorCount = previewData.filter(i => i.hasError).length;
      setImportLog({ 
        success: true, 
        message: "Stock successfully updated.", 
        count: payload.length,
        totalValue: total,
        errorCount,
        dealer: extractedMetadata.dealerName
      });
      setPreviewData([]);
    } else {
      setImportLog({ success: false, message: res.message || "Sync failed.", count: 0, totalValue: 0, errorCount: 0 });
    }
    setImporting(false);
  };

  const shareToWhatsApp = () => {
    if (!importLog) return;

    const summary = `🚀 *Sparezy Inbound Verification*\n\n` +
      `🏢 *Dealer:* ${importLog.dealer || 'Unknown'}\n` +
      `📅 *Date:* ${new Date().toLocaleDateString()}\n` +
      `📦 *Items:* ${importLog.count}\n` +
      `💰 *Total:* ₹${importLog.totalValue.toLocaleString()}\n` +
      `📏 *Standard B.DC:* ${STANDARD_DISCOUNT}%\n` +
      `⚠️ *Discrepancies:* ${importLog.errorCount === 0 ? 'None (Verified ✅)' : importLog.errorCount + ' Issues Found 🚨'}\n\n` +
      `_Automated AI verification completed._`;

    const url = `https://wa.me/?text=${encodeURIComponent(summary)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="h-full flex flex-col bg-[#F8FAFC] md:bg-transparent">

       {!isSearchingOnMobile && (
         <div className="md:hidden bg-white p-4 border-b border-slate-100 z-20 sticky top-0 shadow-sm animate-fade-in">
            <div className="flex bg-slate-100 p-1.5 rounded-2xl">
               <button onClick={() => { setActiveTab('NEW'); setErrorMsg(null); }} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'NEW' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>Entry</button>
               <button onClick={() => { setActiveTab('IMPORT'); setErrorMsg(null); }} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'IMPORT' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400'}`}>Bill Scan</button>
               <button onClick={() => { setActiveTab('HISTORY'); setErrorMsg(null); }} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'HISTORY' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>Log</button>
            </div>
         </div>
       )}

       <div className="hidden md:flex justify-between items-center mb-8 px-1">
          <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Purchase Inbound</h1>
             <p className="text-slate-500 font-medium">Verify bill against standard 12% discount rule.</p>
          </div>
          <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 shadow-soft">
             <button onClick={() => { setActiveTab('NEW'); setErrorMsg(null); }} className={`px-6 py-2.5 text-sm font-bold rounded-xl transition-all flex items-center gap-2 ${activeTab === 'NEW' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}><PlusCircle size={18} /> Manual</button>
             <button onClick={() => { setActiveTab('IMPORT'); setErrorMsg(null); }} className={`px-6 py-2.5 text-sm font-bold rounded-xl transition-all flex items-center gap-2 ${activeTab === 'IMPORT' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}><ScanLine size={18} /> AI Scan</button>
             <button onClick={() => { setActiveTab('HISTORY'); setErrorMsg(null); }} className={`px-6 py-2.5 text-sm font-bold rounded-xl transition-all flex items-center gap-2 ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18} /> History</button>
          </div>
       </div>

       <div className="flex-1 overflow-hidden flex flex-col">
          {activeTab === 'NEW' && <DailyTransactions user={user} forcedMode="PURCHASE" onSearchToggle={setIsSearchingOnMobile} />}

          {activeTab === 'IMPORT' && (
             <div className="max-w-3xl mx-auto w-full p-4 md:p-6 space-y-6 flex flex-col h-full overflow-y-auto no-scrollbar pb-32">
                {!previewData.length && !importLog && (
                  <div className="space-y-6 animate-fade-in">
                    <div className="bg-blue-50 border border-blue-100 rounded-[2.5rem] p-8 flex gap-5 items-start shadow-sm">
                        <div className="p-4 bg-blue-600 text-white rounded-3xl shadow-xl shadow-blue-100 flex-none"><Calculator size={28} /></div>
                        <div>
                            <h3 className="font-black text-blue-900 text-lg uppercase tracking-tight">AI Bill Audit</h3>
                            <p className="text-[14px] text-blue-700/80 mt-2 leading-relaxed font-medium">
                                Upload your bill. Sparezy will automatically extract the <b>Dealer Name</b>, <b>Invoice Date</b>, and check if every item follows the <b>12% B.DC</b> rule.
                            </p>
                        </div>
                    </div>

                    <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-12 text-center hover:border-blue-400 hover:bg-blue-50/20 transition-all group shadow-soft">
                        {importing ? (
                          <div className="py-8"><TharLoader /><p className="mt-8 font-black text-blue-600 animate-pulse text-sm uppercase tracking-widest">Auditing Bill Calculations...</p></div>
                        ) : (
                          <>
                            <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center mx-auto mb-8 group-hover:bg-blue-50 group-hover:text-blue-500 transition-all shadow-inner"><FileText size={44} /></div>
                            <h2 className="text-2xl font-black text-slate-900 mb-2">Import Invoice</h2>
                            <p className="text-slate-400 mb-10 max-w-xs mx-auto text-[14px] font-bold">PDF / Images / Excel supported</p>
                            <label className="inline-flex items-center gap-3 bg-blue-600 hover:bg-blue-700 text-white font-black px-12 py-5 rounded-[2rem] cursor-pointer transition-all active:scale-95 shadow-2xl shadow-blue-200 uppercase text-[13px] tracking-widest">
                               <Upload size={24} /> Select Bill File
                               <input type="file" accept="application/pdf, image/*, .xlsx, .xls, .xlsb, .csv" className="hidden" onChange={handleInvoiceUpload} />
                            </label>
                          </>
                        )}
                        {errorMsg && <div className="mt-10 p-5 bg-red-50 text-red-600 rounded-3xl border border-red-100 text-sm font-black flex items-center gap-3 justify-center animate-shake"><AlertCircle size={20} /> {errorMsg}</div>}
                    </div>
                  </div>
                )}

                {importLog && (
                  <div className={`p-10 rounded-[3rem] border-2 flex flex-col items-center text-center animate-slide-up shadow-2xl bg-white ${importLog.success ? 'border-green-100' : 'border-red-100'}`}>
                      <div className={`w-24 h-24 rounded-full mb-8 flex items-center justify-center shadow-xl ${importLog.success ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                        {importLog.success ? <CheckCircle2 size={48} /> : <AlertCircle size={48} />}
                      </div>
                      <h3 className={`text-3xl font-black ${importLog.success ? 'text-slate-900' : 'text-red-900'}`}>
                        {importLog.success ? 'Import Complete' : 'Process Halted'}
                      </h3>
                      <p className="mt-4 font-bold text-slate-400 text-base max-w-sm leading-relaxed">
                         {importLog.success ? `Stock updated for ${importLog.dealer || 'Dealer'}. ${importLog.errorCount > 0 ? `Alert: Detected ${importLog.errorCount} discrepancies.` : 'Audit passed successfully.'}` : importLog.message}
                      </p>
                      {importLog.success && (
                        <div className="mt-12 space-y-4 w-full">
                            <div className="grid grid-cols-2 gap-5">
                                <div className="bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100 shadow-inner">
                                    <span className="block text-3xl font-black text-slate-900">{importLog.count}</span>
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.25em] mt-1 block">SKUs Synced</span>
                                </div>
                                <div className="bg-blue-50 p-6 rounded-[2.5rem] border border-blue-100 shadow-inner">
                                    <span className="block text-2xl font-black text-blue-900">₹{importLog.totalValue.toLocaleString()}</span>
                                    <span className="text-[10px] font-black text-blue-400 uppercase tracking-[0.25em] mt-1 block">Net Value</span>
                                </div>
                            </div>
                            <div className="flex gap-3">
                                <button onClick={shareToWhatsApp} className="flex-1 bg-green-500 hover:bg-green-600 text-white font-black py-5 rounded-[2rem] shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95"><MessageCircle size={24} /> Share Audit Summary</button>
                                <button onClick={() => setActiveTab('HISTORY')} className="bg-slate-900 text-white p-5 rounded-[2rem] shadow-xl transition-all active:scale-95"><History size={24} /></button>
                            </div>
                        </div>
                      )}
                      <button onClick={() => { setImportLog(null); setPreviewData([]); setErrorMsg(null); }} className="mt-14 text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] hover:text-brand-600 transition-colors">Start New Scan</button>
                  </div>
                )}

                {previewData.length > 0 && (
                  <div className="bg-white rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden animate-slide-up flex flex-col max-h-[85vh]">
                     <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/40">
                        <div className="flex items-center gap-5">
                           <div className="bg-blue-600 text-white p-4 rounded-3xl shadow-xl shadow-blue-100"><ShieldCheck size={28} /></div>
                           <div>
                              <h3 className="font-black text-slate-900 text-xl leading-none mb-2">Audit: {previewData.length} Items</h3>
                              <p className="text-[11px] text-slate-400 font-black uppercase tracking-[0.2em]">Supplier: {extractedMetadata.dealerName || 'Manual'}</p>
                           </div>
                        </div>
                        <button onClick={() => setPreviewData([])} className="p-3 text-slate-300 hover:text-rose-500 bg-white rounded-2xl shadow-sm transition-all active:scale-90"><X size={24} /></button>
                     </div>

                     {extractedMetadata.dealerName && (
                        <div className="bg-blue-50/50 px-8 py-4 border-b border-slate-100 flex flex-wrap gap-6">
                           <div className="flex items-center gap-2">
                              <Building2 size={16} className="text-blue-600" />
                              <span className="text-xs font-bold text-slate-600 uppercase tracking-wider">{extractedMetadata.dealerName}</span>
                           </div>
                           <div className="flex items-center gap-2">
                              <Calendar size={16} className="text-blue-600" />
                              <span className="text-xs font-bold text-slate-600 uppercase tracking-wider">{extractedMetadata.invoiceDate || 'Date N/A'}</span>
                           </div>
                        </div>
                     )}

                     <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar bg-slate-50/30">
                        {previewData.map((row, i) => (
                           <div key={i} className={`bg-white p-6 rounded-[2.5rem] border shadow-sm flex flex-col gap-4 animate-fade-in ${row.hasError ? 'border-rose-200 bg-rose-50/30' : 'border-slate-100'}`} style={{ animationDelay: `${i * 0.05}s` }}>
                              <div className="flex justify-between items-start">
                                 <div className="flex-1 min-w-0 pr-4">
                                    <div className="font-black text-slate-900 text-lg leading-tight tracking-tight mb-1">{row.partNumber}</div>
                                    <div className="text-[12px] text-slate-400 font-bold truncate">{row.name}</div>
                                 </div>
                                 <div className="bg-blue-50 text-blue-600 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase shadow-sm">+{row.quantity} Qty</div>
                              </div>

                              <div className="grid grid-cols-2 md:grid-cols-3 gap-4 pt-4 border-t border-slate-100/50">
                                 <div>
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">MRP</p>
                                    <p className="font-bold text-slate-900">₹{row.mrp.toLocaleString()}</p>
                                 </div>
                                 <div>
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">B.DC Detected</p>
                                    <p className={`font-bold ${row.errorType === 'DISCOUNT_LOW' ? 'text-rose-600' : 'text-slate-900'}`}>
                                      {row.discountPercent}%
                                      {row.errorType === 'DISCOUNT_LOW' && <span className="text-[9px] block">Less than {STANDARD_DISCOUNT}%!</span>}
                                    </p>
                                 </div>
                                 <div className="md:text-right">
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Bill Unit Price</p>
                                    <p className={`font-black text-lg ${row.hasError ? 'text-rose-600' : 'text-teal-600'}`}>₹{row.printedUnitPrice.toLocaleString()}</p>
                                 </div>
                              </div>

                              {row.hasError && (
                                 <div className="bg-rose-100/50 p-4 rounded-2xl border border-rose-200 flex gap-3 items-center">
                                    <AlertTriangle className="text-rose-600" size={20} />
                                    <div className="text-[12px] font-bold text-rose-800 leading-tight">
                                       {row.errorType === 'DISCOUNT_LOW' ? (
                                          <p>Error: Bill discount ({row.discountPercent}%) is lower than standard ({STANDARD_DISCOUNT}%).</p>
                                       ) : (
                                          <p>Price Mismatch! At {STANDARD_DISCOUNT}% B.DC, expected ₹{row.calculatedPrice.toLocaleString()}</p>
                                       )}
                                       <p className="opacity-70 mt-1">Discrepancy of ₹{row.diff.toLocaleString()} detected per unit.</p>
                                    </div>
                                 </div>
                              )}
                           </div>
                        ))}
                     </div>

                     <div className="p-8 border-t border-slate-100 bg-white sticky bottom-0">
                        <button onClick={confirmBulkImport} disabled={importing} className="w-full bg-slate-900 hover:bg-black text-white font-black py-5.5 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.15)] flex items-center justify-center gap-4 active:scale-[0.98] transition-all disabled:opacity-50 text-[16px] uppercase tracking-widest">
                          {importing ? <Loader2 className="animate-spin" /> : <CheckCircle2 size={24} />} Confirm Audit & Sync
                        </button>
                     </div>
                  </div>
                )}
             </div>
          )}

          {activeTab === 'HISTORY' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-[3rem] shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-8 border-b border-slate-100 bg-white flex items-center justify-between">
                   <div className="flex items-center gap-4">
                      <div className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-100"><Truck size={24} /></div>
                      <div>
                         <span className="font-black text-slate-900 text-xl tracking-tight block">Inbound Log</span>
                         <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Verified Purchase History</span>
                      </div>
                   </div>
                   <button onClick={loadHistory} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-slate-100 active:scale-95 transition-all"><Clock size={20} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-4 no-scrollbar pb-32">
                  {loading ? <div className="flex justify-center p-20"><TharLoader /></div> : history.length === 0 ? <div className="flex flex-col items-center justify-center py-32 text-slate-300"><div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mb-8 shadow-soft"><History size={48} className="opacity-10" /></div><p className="font-black text-xs uppercase tracking-[0.3em]">No history found</p></div> : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {history.map(tx => (
                            <div key={tx.id} className="p-6 bg-white rounded-[2.5rem] border border-slate-100 shadow-premium animate-fade-in relative group overflow-hidden">
                                <div className="absolute top-0 right-0 w-3 h-full bg-blue-600/10 group-hover:bg-blue-600/20 transition-all"></div>
                                <div className="flex justify-between items-start mb-5">
                                    <div className="space-y-1.5 flex-1 min-w-0 pr-4">
                                        <div className="font-black text-slate-900 text-lg leading-tight tracking-tight truncate">{tx.partNumber}</div>
                                        <div className="flex items-center gap-2 text-slate-400 text-[10px] font-black uppercase tracking-widest"><Calendar size={12} className="text-slate-300" /> {new Date(tx.createdAt).toLocaleDateString()}</div>
                                    </div>
                                    <div className="bg-blue-50 text-blue-600 px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-[0.1em] shadow-sm">+{tx.quantity}</div>
                                </div>
                                <div className="mt-6 pt-5 border-t border-slate-50 flex justify-between items-end">
                                    <div className="flex-1 min-w-0 pr-4"><p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1.5">Source</p><p className="text-[13px] font-bold text-slate-700 truncate">{tx.customerName || 'Manual Entry'}</p></div>
                                    <div className="text-right"><p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1.5">Net Rate</p><p className="text-xl font-black text-slate-900 tracking-tighter">₹{tx.price.toLocaleString()}</p></div>
                                </div>
                            </div>
                        ))}
                    </div>
                  )}
                </div>
             </div>
          )}
       </div>
    </div>
  );
};

export default Purchases;

import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction, TransactionStatus, TransactionType, Role } from '../types';
import DailyTransactions from './DailyTransactions'; 
import { 
  History, 
  PlusCircle, 
  User as UserIcon, 
  Undo2, 
  Search, 
  CheckCircle2, 
  AlertCircle, 
  Clock, 
  Calendar, 
  Minus, 
  Plus, 
  Loader2,
  Filter,
  ArrowUpDown,
  ChevronDown,
  X,
  TrendingDown,
  TrendingUp,
  Banknote,
  Layers,
  List,
  ChevronRight,
  Package,
  ArrowLeft
} from 'lucide-react';
import { createBulkTransactions, fetchTransactions } from '../services/transactionService';
import TharLoader from '../components/TharLoader';

interface Props {
  user: User;
}

type SortField = 'date' | 'amount';
type SortOrder = 'asc' | 'desc';
type ViewMode = 'LIST' | 'STACKED';

interface GroupedBill {
  id: string; // usually first tx id
  createdAt: string;
  customerName: string;
  type: TransactionType;
  items: Transaction[];
  totalAmount: number;
}

const Billing: React.FC<Props> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'NEW' | 'RETURN' | 'HISTORY'>('NEW');
  const [viewMode, setViewMode] = useState<ViewMode>('STACKED');
  const [history, setHistory] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [isSearchingOnMobile, setIsSearchingOnMobile] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Modal for Bill Detail
  const [selectedBill, setSelectedBill] = useState<GroupedBill | null>(null);

  // --- HISTORY FILTERS & SORTING STATE ---
  const [historySearch, setHistorySearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<'ALL' | TransactionType.SALE | TransactionType.RETURN>('ALL');
  const [dateRange, setDateRange] = useState<'ALL' | 'TODAY' | 'WEEK' | 'MONTH'>('ALL');
  const [minAmount, setMinAmount] = useState<string>('');
  const [maxAmount, setMaxAmount] = useState<string>('');
  const [sortBy, setSortBy] = useState<SortField>('date');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  // --- RETURN TAB STATE ---
  const [salesLog, setSalesLog] = useState<Transaction[]>([]);
  const [returnSearch, setReturnSearch] = useState('');
  const [selectedReturns, setSelectedReturns] = useState<Record<string, number>>({}); 
  const [processingReturns, setProcessingReturns] = useState(false);
  const [alreadyReturnedMap, setAlreadyReturnedMap] = useState<Map<string, number>>(new Map());

  useEffect(() => {
    if (activeTab === 'HISTORY') {
      loadHistory();
    }
    if (activeTab === 'RETURN') {
      loadSalesForReturn();
    }
  }, [activeTab]);

  const loadHistory = async () => {
    setLoading(true);
    const data = await fetchTransactions(
      TransactionStatus.APPROVED, 
      [TransactionType.SALE, TransactionType.RETURN]
    );
    setHistory(data);
    setLoading(false);
  };

  const loadSalesForReturn = async () => {
    setLoading(true);
    const salesData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.SALE);
    const returnsData = await fetchTransactions(TransactionStatus.APPROVED, TransactionType.RETURN);

    const returnedMap = new Map<string, number>();
    returnsData.forEach(r => {
        if (r.relatedTransactionId) {
            const current = returnedMap.get(r.relatedTransactionId) || 0;
            returnedMap.set(r.relatedTransactionId, current + r.quantity);
        }
    });
    setAlreadyReturnedMap(returnedMap);

    const availableSales = salesData.filter(sale => {
        const returnedQty = returnedMap.get(sale.id) || 0;
        return sale.quantity > returnedQty;
    });

    setSalesLog(availableSales);
    setLoading(false);
  };

  // --- COMPUTED FILTERED HISTORY ---
  const filteredHistory = useMemo(() => {
    let result = [...history];

    if (historySearch) {
      const s = historySearch.toLowerCase();
      result = result.filter(tx => 
        tx.partNumber.toLowerCase().includes(s) || 
        tx.customerName.toLowerCase().includes(s)
      );
    }

    if (typeFilter !== 'ALL') {
      result = result.filter(tx => tx.type === typeFilter);
    }

    if (dateRange !== 'ALL') {
      const now = new Date();
      const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

      result = result.filter(tx => {
        const txTime = new Date(tx.createdAt).getTime();
        if (dateRange === 'TODAY') return txTime >= startOfToday;
        if (dateRange === 'WEEK') return txTime >= (now.getTime() - 7 * 24 * 60 * 60 * 1000);
        if (dateRange === 'MONTH') return txTime >= (now.getTime() - 30 * 24 * 60 * 60 * 1000);
        return true;
      });
    }

    const min = parseFloat(minAmount);
    const max = parseFloat(maxAmount);
    if (!isNaN(min)) result = result.filter(tx => (tx.price * tx.quantity) >= min);
    if (!isNaN(max)) result = result.filter(tx => (tx.price * tx.quantity) <= max);

    return result;
  }, [history, historySearch, typeFilter, dateRange, minAmount, maxAmount]);

  // --- GROUPING LOGIC FOR STACKED VIEW ---
  const stackedHistory = useMemo(() => {
    const groups: Record<string, GroupedBill> = {};

    filteredHistory.forEach(tx => {
      // Group key: exact timestamp + customer name
      const key = `${tx.createdAt}_${tx.customerName}_${tx.type}`;
      if (!groups[key]) {
        groups[key] = {
          id: tx.id,
          createdAt: tx.createdAt,
          customerName: tx.customerName,
          type: tx.type,
          items: [],
          totalAmount: 0
        };
      }
      groups[key].items.push(tx);
      groups[key].totalAmount += (tx.price * tx.quantity);
    });

    const result = Object.values(groups);

    // Sort the stacks
    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : a.totalAmount;
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : b.totalAmount;

      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });

    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  // Final list for simple view sorting
  const sortedListHistory = useMemo(() => {
    const result = [...filteredHistory];
    result.sort((a, b) => {
      let valA = sortBy === 'date' ? new Date(a.createdAt).getTime() : (a.price * a.quantity);
      let valB = sortBy === 'date' ? new Date(b.createdAt).getTime() : (b.price * b.quantity);
      if (sortOrder === 'asc') return valA - valB;
      return valB - valA;
    });
    return result;
  }, [filteredHistory, sortBy, sortOrder]);

  const handleReturnToggle = (tx: Transaction) => {
    const newSelection = { ...selectedReturns };
    if (newSelection[tx.id]) {
      delete newSelection[tx.id];
    } else {
      const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
      const remaining = tx.quantity - prevReturned;
      newSelection[tx.id] = remaining > 0 ? remaining : 0;
    }
    setSelectedReturns(newSelection);
  };

  const handleReturnQtyChange = (txId: string, maxQty: number, newQty: string) => {
    let qty = parseInt(newQty);
    if (isNaN(qty)) qty = 0;
    if (qty > maxQty) qty = maxQty;
    if (qty < 0) qty = 0;

    if (qty === 0) {
      const newSelection = { ...selectedReturns };
      delete newSelection[txId];
      setSelectedReturns(newSelection);
    } else {
      setSelectedReturns({ ...selectedReturns, [txId]: qty });
    }
  };

  const submitReturns = async () => {
    const ids = Object.keys(selectedReturns);
    if (ids.length === 0) return;
    if (!confirm(`Process returns for ${ids.length} items?`)) return;

    setProcessingReturns(true);
    const returnPayload = ids.map(id => {
       const originalSale = salesLog.find(s => s.id === id);
       if (!originalSale) return null;
       return {
         partNumber: originalSale.partNumber,
         type: TransactionType.RETURN,
         quantity: selectedReturns[id],
         price: originalSale.price,
         customerName: originalSale.customerName || 'Customer Return',
         createdByRole: user.role,
         relatedTransactionId: originalSale.id
       };
    }).filter(Boolean) as any[];

    const res = await createBulkTransactions(returnPayload);
    setProcessingReturns(false);

    if (res.success) {
       alert("Returns processed successfully.");
       setSelectedReturns({});
       loadSalesForReturn();
    } else {
       alert("Failed to process returns: " + res.message);
    }
  };

  const filteredSalesLog = salesLog.filter(tx => 
     tx.partNumber.toLowerCase().includes(returnSearch.toLowerCase()) ||
     (tx.customerName && tx.customerName.toLowerCase().includes(returnSearch.toLowerCase()))
  );

  const totalRefundAmount = Object.keys(selectedReturns).reduce((acc, id) => {
     const tx = salesLog.find(s => s.id === id);
     return acc + (tx ? (tx.price * selectedReturns[id]) : 0);
  }, 0);

  const clearFilters = () => {
    setHistorySearch('');
    setTypeFilter('ALL');
    setDateRange('ALL');
    setMinAmount('');
    setMaxAmount('');
    setSortBy('date');
    setSortOrder('desc');
  };

  return (
    <div className="h-full flex flex-col bg-slate-50 md:bg-transparent">

       {!isSearchingOnMobile && (
         <div className="md:hidden bg-white p-4 border-b border-slate-100 z-20 sticky top-0 shadow-sm animate-fade-in">
            <div className="flex bg-slate-100 p-1 rounded-2xl">
               <button 
                 onClick={() => setActiveTab('NEW')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'NEW' ? 'bg-white text-brand-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 POS
               </button>
               <button 
                 onClick={() => setActiveTab('RETURN')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'RETURN' ? 'bg-white text-rose-600 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 Returns
               </button>
               <button 
                 onClick={() => setActiveTab('HISTORY')}
                 className={`flex-1 py-2.5 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'HISTORY' ? 'bg-white text-slate-800 shadow-md ring-1 ring-slate-100' : 'text-slate-400'}`}
               >
                 History
               </button>
            </div>
         </div>
       )}

       <div className="hidden md:flex justify-between items-center mb-6">
          <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Counter Sales</h1>
             <p className="text-slate-500 font-medium">Record retail transactions and customer returns.</p>
          </div>
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-soft">
             <button onClick={() => setActiveTab('NEW')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'NEW' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <PlusCircle size={18} /> New Sale
             </button>
             <button onClick={() => setActiveTab('RETURN')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'RETURN' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <Undo2 size={18} /> Process Return
             </button>
             <button onClick={() => setActiveTab('HISTORY')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
               <History size={18} /> Recent History
             </button>
          </div>
       </div>

       <div className="flex-1 overflow-hidden flex flex-col relative">
          {activeTab === 'NEW' && (
             <DailyTransactions 
                user={user} 
                forcedMode="SALES" 
                onSearchToggle={setIsSearchingOnMobile} 
             />
          )}

          {activeTab === 'RETURN' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 text-rose-600 font-black text-base w-full md:w-auto">
                      <div className="p-2 bg-rose-50 rounded-xl"><Undo2 size={20} /></div>
                      SELECT ITEMS TO RETURN
                   </div>
                   <div className="w-full md:w-auto flex-1 md:max-w-xs relative">
                       <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                       <input 
                          type="text" 
                          placeholder="Search Part No. or Customer..."
                          className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-2xl text-sm font-bold shadow-inner focus:ring-2 focus:ring-rose-500/20"
                          value={returnSearch}
                          onChange={e => setReturnSearch(e.target.value)}
                       />
                   </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
                   {loading ? (
                      <div className="flex justify-center p-12"><TharLoader /></div>
                   ) : filteredSalesLog.length === 0 ? (
                      <div className="flex flex-col items-center justify-center py-24 text-slate-300">
                         <AlertCircle size={64} className="mb-4 opacity-10" />
                         <p className="font-black text-xs uppercase tracking-widest">No compatible sales found</p>
                      </div>
                   ) : (
                      <div className="pb-24 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {filteredSalesLog.map(tx => {
                            const isSelected = !!selectedReturns[tx.id];
                            const prevReturned = alreadyReturnedMap.get(tx.id) || 0;
                            const remainingQty = tx.quantity - prevReturned;
                            const returnQty = selectedReturns[tx.id] || remainingQty;

                            return (
                                <div 
                                    key={tx.id} 
                                    onClick={() => handleReturnToggle(tx)}
                                    className={`p-5 rounded-[2rem] border transition-all cursor-pointer bg-white ${isSelected ? 'border-rose-500 ring-2 ring-rose-500/10 shadow-lg' : 'border-slate-100 hover:border-slate-200 shadow-sm'}`}
                                >
                                    <div className="flex justify-between items-start mb-4">
                                        <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-rose-50 border-rose-50 text-white' : 'bg-slate-50 border-slate-200 text-transparent'}`}>
                                            <CheckCircle2 size={14} />
                                        </div>
                                        <div className="text-right">
                                            <div className="text-[9px] font-black text-slate-400 uppercase mb-0.5">Sold On</div>
                                            <div className="text-[11px] font-bold text-slate-900">{new Date(tx.createdAt).toLocaleDateString()}</div>
                                        </div>
                                    </div>

                                    <div className="mb-4">
                                        <div className="font-black text-lg text-slate-900 leading-tight">{tx.partNumber}</div>
                                        <div className="text-[13px] text-slate-400 font-medium flex items-center gap-1.5 mt-1">
                                            <UserIcon size={14} className="text-slate-300" /> {tx.customerName || 'Walk-in Customer'}
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-end border-t border-slate-50 pt-4">
                                        <div className="space-y-1">
                                            <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Original Sale</div>
                                            <div className="font-black text-slate-900">{tx.quantity} <span className="text-[10px] text-slate-400">units</span></div>
                                            <div className="text-[9px] font-black text-teal-600 bg-teal-50 px-1.5 py-0.5 rounded-md inline-block">Rem: {remainingQty}</div>
                                        </div>

                                        {isSelected && (
                                            <div onClick={e => e.stopPropagation()} className="bg-rose-50 p-2 rounded-2xl border border-rose-100 flex flex-col items-center">
                                                <span className="text-[9px] font-black text-rose-500 uppercase mb-1">Return Qty</span>
                                                <div className="flex items-center gap-2 bg-white px-2 py-1 rounded-xl shadow-sm">
                                                    <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (returnQty - 1).toString())} className="w-8 h-8 rounded-lg flex items-center justify-center text-rose-500"><Minus size={14}/></button>
                                                    <span className="font-black text-slate-900 min-w-[20px] text-center">{returnQty}</span>
                                                    <button onClick={() => handleReturnQtyChange(tx.id, remainingQty, (returnQty + 1).toString())} className="w-8 h-8 bg-rose-500 text-white rounded-lg flex items-center justify-center"><Plus size={14}/></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            )
                        })}
                      </div>
                   )}
                </div>

                {/* Return Fixed Footer */}
                <div className="fixed bottom-0 md:bottom-6 left-0 md:left-auto right-0 md:right-8 bg-white md:rounded-3xl border-t md:border border-slate-100 p-5 shadow-[0_-10px_40px_rgba(0,0,0,0.05)] md:shadow-2xl z-[90] pb-safe flex justify-between items-center md:min-w-[400px]">
                   <div className="flex-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Refund Total ({Object.keys(selectedReturns).length})</p>
                      <p className="text-2xl font-black text-rose-600 tracking-tight">₹{totalRefundAmount.toLocaleString()}</p>
                   </div>

                   <button 
                      onClick={submitReturns}
                      disabled={Object.keys(selectedReturns).length === 0 || processingReturns}
                      className="bg-rose-600 hover:bg-rose-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-rose-200 transition-all flex items-center gap-3 active:scale-95 disabled:opacity-30 disabled:shadow-none"
                   >
                      {processingReturns ? <Loader2 className="animate-spin" size={20} /> : <CheckCircle2 size={20} />}
                      Process
                   </button>
                </div>
             </div>
          )}

          {activeTab === 'HISTORY' && (
             <div className="bg-[#F8FAFC] md:bg-white md:rounded-3xl shadow-soft border border-slate-100 flex flex-col h-full overflow-hidden">
                <div className="p-4 md:p-6 border-b border-slate-100 bg-white flex flex-col lg:flex-row justify-between items-center gap-4">
                   <div className="flex items-center gap-3 w-full md:w-auto">
                      <div className="p-2 bg-slate-900 text-white rounded-xl"><History size={18} /></div>
                      <span className="font-black text-slate-900 text-base uppercase tracking-tight">Financial Journal</span>

                      <div className="ml-4 flex bg-slate-100 p-1 rounded-xl">
                          <button onClick={() => setViewMode('STACKED')} className={`p-2 rounded-lg transition-all ${viewMode === 'STACKED' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`} title="Bill Stack View"><Layers size={16} /></button>
                          <button onClick={() => setViewMode('LIST')} className={`p-2 rounded-lg transition-all ${viewMode === 'LIST' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400'}`} title="Item List View"><List size={16} /></button>
                      </div>
                   </div>

                   <div className="flex items-center gap-2 w-full md:w-auto overflow-x-auto no-scrollbar pb-1 md:pb-0">
                      <div className="relative flex-1 md:w-64">
                         <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                         <input 
                           type="text" 
                           placeholder="Search History..." 
                           className="w-full pl-10 pr-4 py-2 bg-slate-50 border-none rounded-xl text-sm font-bold shadow-inner focus:ring-2 focus:ring-slate-200"
                           value={historySearch}
                           onChange={e => setHistorySearch(e.target.value)}
                         />
                      </div>
                      <button 
                        onClick={() => setShowFilters(!showFilters)}
                        className={`p-2 rounded-xl border transition-all flex items-center gap-2 whitespace-nowrap text-xs font-bold ${showFilters ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
                      >
                         <Filter size={16} /> Filters {(typeFilter !== 'ALL' || dateRange !== 'ALL' || minAmount || maxAmount) && "•"}
                      </button>
                      <button 
                        onClick={loadHistory}
                        className="p-2 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-slate-600 transition-all"
                      >
                         <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                      </button>
                   </div>
                </div>

                {showFilters && (
                  <div className="bg-white border-b border-slate-100 p-4 md:p-6 animate-slide-down">
                    <div className="max-w-5xl mx-auto grid grid-cols-2 md:grid-cols-4 gap-4">
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tx Type</label>
                          <select 
                            className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                            value={typeFilter}
                            onChange={e => setTypeFilter(e.target.value as any)}
                          >
                             <option value="ALL">All Types</option>
                             <option value={TransactionType.SALE}>Sales Only</option>
                             <option value={TransactionType.RETURN}>Returns Only</option>
                          </select>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Period</label>
                          <select 
                            className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                            value={dateRange}
                            onChange={e => setDateRange(e.target.value as any)}
                          >
                             <option value="ALL">All Time</option>
                             <option value="TODAY">Today</option>
                             <option value="WEEK">Last 7 Days</option>
                             <option value="MONTH">Last 30 Days</option>
                          </select>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Amount Range (₹)</label>
                          <div className="flex items-center gap-2">
                             <input 
                               type="number" 
                               placeholder="Min" 
                               className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                               value={minAmount}
                               onChange={e => setMinAmount(e.target.value)}
                             />
                             <span className="text-slate-300">-</span>
                             <input 
                               type="number" 
                               placeholder="Max" 
                               className="w-full bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                               value={maxAmount}
                               onChange={e => setMaxAmount(e.target.value)}
                             />
                          </div>
                       </div>
                       <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sort Order</label>
                          <div className="flex gap-2">
                            <select 
                                className="flex-1 bg-slate-50 border-none rounded-xl text-xs font-bold p-2.5 focus:ring-2 focus:ring-slate-100"
                                value={sortBy}
                                onChange={e => setSortBy(e.target.value as any)}
                            >
                                <option value="date">Date</option>
                                <option value="amount">Amount</option>
                            </select>
                            <button 
                                onClick={() => setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc')}
                                className="bg-slate-50 p-2.5 rounded-xl text-slate-500 hover:text-slate-900 transition-colors"
                            >
                                <ArrowUpDown size={16} />
                            </button>
                          </div>
                       </div>
                    </div>
                    <div className="flex justify-end mt-4">
                       <button onClick={clearFilters} className="text-[10px] font-black text-rose-500 uppercase tracking-widest hover:underline">Reset All Filters</button>
                    </div>
                  </div>
                )}

                <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar pb-24">
                  {loading ? (
                    <div className="flex justify-center p-12"><TharLoader /></div>
                  ) : (viewMode === 'LIST' ? sortedListHistory : stackedHistory).length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-24 text-slate-300">
                        <AlertCircle size={64} className="mb-4 opacity-10" />
                        <p className="font-black text-xs uppercase tracking-widest">No entries found matching filters</p>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {viewMode === 'LIST' ? (
                        sortedListHistory.map(tx => {
                            const isReturn = tx.type === TransactionType.RETURN;
                            const amount = tx.price * tx.quantity;
                            return (
                                <div key={tx.id} className="p-5 rounded-[2.5rem] bg-white border border-slate-100 shadow-sm flex flex-col animate-fade-in relative overflow-hidden group">
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="space-y-1">
                                            <div className="font-black text-slate-900 text-lg leading-tight group-hover:text-brand-600 transition-colors">{tx.partNumber}</div>
                                            <div className="flex items-center gap-1.5 text-slate-400 text-[11px] font-bold">
                                                <Calendar size={12} /> {new Date(tx.createdAt).toLocaleDateString()}
                                                <span className="text-slate-200">|</span>
                                                <Clock size={12} /> {new Date(tx.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                            </div>
                                        </div>
                                        <div className={`px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest ${isReturn ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>
                                            {tx.type}
                                        </div>
                                    </div>
                                    <div className="bg-slate-50/50 p-3 rounded-2xl border border-slate-50 flex items-center gap-3 mb-5">
                                        <UserIcon size={14} className="text-slate-300" />
                                        <div className="flex-1 min-w-0">
                                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-0.5">Billed To</p>
                                            <p className="text-[13px] font-bold text-slate-800 truncate">{tx.customerName || 'Walk-in'}</p>
                                        </div>
                                    </div>
                                    <div className="mt-auto flex justify-between items-center">
                                        <span className="bg-slate-100 px-3 py-1 rounded-xl text-[11px] font-black text-slate-500 uppercase tracking-widest">{tx.quantity} units</span>
                                        <p className={`text-xl font-black tracking-tight ${isReturn ? 'text-rose-600' : 'text-slate-900'}`}>₹{amount.toLocaleString()}</p>
                                    </div>
                                </div>
                            )
                        })
                      ) : (
                        stackedHistory.map(bill => {
                            const isReturn = bill.type === TransactionType.RETURN;
                            return (
                                <div 
                                    key={bill.id} 
                                    onClick={() => setSelectedBill(bill)}
                                    className="p-6 rounded-[2.5rem] bg-white border-2 border-slate-100 shadow-premium hover:border-slate-300 hover:shadow-xl transition-all cursor-pointer group relative animate-fade-in"
                                >
                                    {/* Stack effect bars */}
                                    <div className="absolute -bottom-2 left-8 right-8 h-2 bg-slate-200 rounded-b-3xl -z-10 group-hover:-bottom-3 transition-all opacity-40"></div>
                                    <div className="absolute -bottom-4 left-14 right-14 h-2 bg-slate-100 rounded-b-3xl -z-20 group-hover:-bottom-5 transition-all opacity-20"></div>

                                    <div className="flex justify-between items-start mb-6">
                                        <div className="space-y-1.5">
                                            <div className="flex items-center gap-2">
                                                <div className={`p-1.5 rounded-lg ${isReturn ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>
                                                    {isReturn ? <Undo2 size={16}/> : <PlusCircle size={16}/>}
                                                </div>
                                                <span className={`text-[10px] font-black uppercase tracking-[0.2em] ${isReturn ? 'text-rose-500' : 'text-teal-600'}`}>
                                                    {bill.type} Bill
                                                </span>
                                            </div>
                                            <div className="text-[11px] font-bold text-slate-400 flex items-center gap-2">
                                                <Calendar size={12}/> {new Date(bill.createdAt).toLocaleDateString()}
                                                <span className="text-slate-200">•</span>
                                                <Clock size={12}/> {new Date(bill.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                            </div>
                                        </div>
                                        <div className="bg-slate-900 text-white w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg active:scale-90 transition-all">
                                            <ChevronRight size={20} />
                                        </div>
                                    </div>

                                    <div className="mb-6">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5">Customer</p>
                                        <div className="font-black text-lg text-slate-900 leading-tight truncate group-hover:text-brand-600 transition-colors">
                                            {bill.customerName || 'Standard Checkout'}
                                        </div>
                                    </div>

                                    <div className="flex justify-between items-end border-t border-slate-50 pt-5 mt-auto">
                                        <div className="bg-slate-50 px-3 py-1.5 rounded-xl border border-slate-100 flex items-center gap-2">
                                            <Package size={14} className="text-slate-400"/>
                                            <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">{bill.items.length} Parts</span>
                                        </div>
                                        <div className="text-right">
                                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Bill Total</p>
                                            <p className={`text-2xl font-black tracking-tighter ${isReturn ? 'text-rose-600' : 'text-slate-900'}`}>
                                                ₹{bill.totalAmount.toLocaleString()}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            )
                        })
                      )}
                    </div>
                  )}
                </div>
             </div>
          )}
       </div>

       {/* BILL DETAIL MODAL */}
       {selectedBill && (
          <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 lg:p-8 animate-fade-in">
              <div 
                className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden animate-slide-up"
              >
                  <div className="p-8 md:p-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/40">
                      <div className="flex items-center gap-5">
                          <button onClick={() => setSelectedBill(null)} className="p-3 bg-white text-slate-400 hover:text-slate-900 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-90"><ArrowLeft size={24}/></button>
                          <div>
                              <h3 className="font-black text-slate-900 text-2xl tracking-tight leading-none mb-2">{selectedBill.customerName || 'Cash Bill'}</h3>
                              <div className="flex items-center gap-3 text-slate-400 text-sm font-bold uppercase tracking-widest">
                                  <Calendar size={14}/> {new Date(selectedBill.createdAt).toLocaleDateString()}
                                  <span className="text-slate-200">|</span>
                                  <Clock size={14}/> {new Date(selectedBill.createdAt).toLocaleTimeString()}
                              </div>
                          </div>
                      </div>
                      <div className={`hidden md:block px-5 py-2.5 rounded-2xl text-sm font-black uppercase tracking-widest ${selectedBill.type === 'RETURN' ? 'bg-rose-50 text-rose-600' : 'bg-teal-50 text-teal-600'}`}>
                          {selectedBill.type} INVOICE
                      </div>
                  </div>

                  <div className="flex-1 overflow-y-auto p-6 md:p-10 no-scrollbar space-y-4">
                      <div className="flex items-center gap-3 mb-4">
                         <div className="w-1.5 h-6 bg-brand-600 rounded-full"></div>
                         <h4 className="font-black text-slate-900 uppercase tracking-widest text-sm">Line Items ({selectedBill.items.length})</h4>
                      </div>

                      <div className="space-y-3">
                          {selectedBill.items.map((item, idx) => (
                              <div key={item.id} className="p-6 bg-slate-50/50 rounded-3xl border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4 group hover:bg-white hover:border-brand-100 hover:shadow-md transition-all">
                                  <div className="flex items-center gap-5">
                                      <div className="w-12 h-12 bg-white rounded-2xl border border-slate-100 flex items-center justify-center font-black text-slate-300 text-sm">{idx + 1}</div>
                                      <div className="min-w-0">
                                          <div className="font-black text-slate-900 text-lg leading-tight tracking-tight group-hover:text-brand-600 transition-colors">{item.partNumber}</div>
                                          <p className="text-[13px] text-slate-400 font-bold uppercase tracking-widest mt-1">Net Rate: ₹{item.price.toLocaleString()}</p>
                                      </div>
                                  </div>
                                  <div className="flex items-center justify-between md:justify-end gap-12 border-t md:border-t-0 border-slate-100 pt-4 md:pt-0">
                                      <div className="text-center md:text-right">
                                          <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-0.5">Quantity</p>
                                          <p className="text-xl font-black text-slate-900">{item.quantity}</p>
                                      </div>
                                      <div className="text-right">
                                          <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-0.5">Subtotal</p>
                                          <p className="text-xl font-black text-slate-900 tracking-tight">₹{(item.price * item.quantity).toLocaleString()}</p>
                                      </div>
                                  </div>
                              </div>
                          ))}
                      </div>
                  </div>

                  <div className="p-8 md:p-10 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-6">
                      <div className="flex items-center gap-5">
                          <div className="p-4 bg-slate-900 text-white rounded-3xl shadow-xl"><Banknote size={32} /></div>
                          <div>
                              <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Final Bill Amount</p>
                              <p className={`text-4xl font-black tracking-tighter ${selectedBill.type === 'RETURN' ? 'text-rose-600' : 'text-slate-900'}`}>
                                  {selectedBill.type === 'RETURN' ? '-' : ''}₹{selectedBill.totalAmount.toLocaleString()}
                              </p>
                          </div>
                      </div>
                      <button onClick={() => setSelectedBill(null)} className="w-full md:w-auto bg-slate-100 hover:bg-slate-200 text-slate-600 font-black px-12 py-5 rounded-[2rem] transition-all active:scale-95 uppercase text-xs tracking-widest">Close View</button>
                  </div>
              </div>
          </div>
       )}
    </div>
  );
};

